{
  "grammar": [
    {
      "pattern": "吃 + (量詞) + 藥 + (時間/頻率)",
      "structure": ["verb", "measure word", "object", "time/frequency"],
      "explanation_en": "Use this pattern to talk about taking medicine, specifying the type, dosage, and frequency.",
      "title": "Taking Medicine (吃藥)",
      "meaning": "To take medicine",
      "when_to_use": ["When describing medication intake", "When asking about dosage or frequency"],
      "when_not_to_use": ["When talking about applying ointment (use 擦藥膏 instead)", "When referring to injections (use 打針)"],
      "pragmatic_notes": "In Taiwan, 藥師 (pharmacist) is commonly used at 藥房 (pharmacy). You can ask 藥師 for advice on 成藥 (over-the-counter medicine).",
      "word_order_notes": "Time/frequency usually comes after the object, e.g., 吃藥一天三次.",
      "english_contrast": "English says 'take medicine three times a day'; Chinese order is 'eat medicine one day three times'.",
      "korean_contrast": "Korean uses '약을 먹다' (eat medicine) similarly, but frequency often precedes the verb.",
      "negative_examples": [
        {
          "text": "我吃藥水一天。",
          "error": "Incorrect word order; should be 我一天吃一次藥水."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我吃藥丸兩次。",
          "error": "Missing time frame; should specify 一天兩次."
        }
      ],
      "transformation_drills": ["Change 我吃藥一天三次 to 我一天吃三次藥.", "Change 他吃藥水一天兩次 to 他一天吃兩次藥水."],
      "production_drills": ["Ask your partner: 你一天吃幾次藥？", "Tell the pharmacist: 我一天吃三次藥丸。"],
      "common_error_patterns": ["Omitting time frame", "Using wrong measure word for liquid medicine (should be 次, not 杯)"],
      "repair_feedback": {
        "word_order": "Put time/frequency after the object, e.g., 吃藥一天三次.",
        "politeness": "Use 請問 when asking the pharmacist.",
        "vocabulary": "Use 藥水 for liquid medicine, 藥丸 for pills."
      }
    },
    {
      "pattern": "每天 + 次數 + 動詞 + 藥",
      "structure": ["frequency phrase", "verb", "object"],
      "explanation_en": "Use this pattern to express how many times per day you do something, especially taking medicine.",
      "title": "Frequency per Day (每天...次)",
      "meaning": "How many times a day",
      "when_to_use": ["When stating daily medication frequency", "When asking about daily habits"],
      "when_not_to_use": ["When talking about total dosage (use 總共 instead)", "When referring to weekly frequency (use 每星期)"],
      "pragmatic_notes": "In Taiwan, doctors often say 一天三次, 飯後 (three times a day, after meals). 飯前 means before meals, 睡前 means before sleep.",
      "word_order_notes": "每天 comes first, then the number of times, then the verb and object.",
      "english_contrast": "English says 'take medicine three times a day'; Chinese says 'every day three times take medicine'.",
      "korean_contrast": "Korean uses '하루에 세 번' (three times a day) similarly placed before the verb.",
      "negative_examples": [
        {
          "text": "我吃藥每天三次。",
          "error": "每天 should come before the verb phrase."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我每天吃藥。",
          "error": "Missing the number of times; should specify 每天三次."
        }
      ],
      "transformation_drills": ["Change 我每天吃藥三次 to 我一天吃三次藥.", "Change 他每天吃藥水兩次 to 他一天吃兩次藥水."],
      "production_drills": ["Ask: 你每天吃幾次藥？", "Answer: 我每天吃兩次藥丸。"],
      "common_error_patterns": ["Forgetting to specify the number of times", "Using 每天 with 一次 incorrectly placed"],
      "repair_feedback": {
        "word_order": "Place 每天 at the beginning of the sentence.",
        "politeness": "Use 請問 when asking about medication.",
        "vocabulary": "Use 次 for times, 藥丸 for pills, 藥水 for liquid."
      }
    },
    {
      "pattern": "可以 + 動詞 + 嗎？ / 不可以 + 動詞",
      "structure": ["modal verb", "verb", "question/negation"],
      "explanation_en": "Use 可以 to ask for permission or possibility, and 不可以 to deny permission, especially in medical contexts.",
      "title": "Permission and Possibility (可以/不可以)",
      "meaning": "Can / Cannot",
      "when_to_use": ["When asking if you can take medicine", "When asking if something is allowed", "When denying permission"],
      "when_not_to_use": ["When talking about ability (use 會 instead)", "When making polite requests (use 請 or 不好意思)"],
      "pragmatic_notes": "In Taiwan, at a 診所 (clinic), you can ask 醫生: 我可以吃這個藥嗎？ (Can I take this medicine?). 不可以 is direct; use 不能 for softer negation.",
      "word_order_notes": "可以 comes before the verb; 嗎 at the end for questions.",
      "english_contrast": "English uses 'can' similarly, but Chinese places 可以 before the verb.",
      "korean_contrast": "Korean uses '~을/를 먹어도 돼요?' (can I eat?) similarly structured.",
      "negative_examples": [
        {
          "text": "我可以吃藥嗎？可以。",
          "error": "Correct, but avoid using 可以 alone as answer; use 可以 or 可以啊."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我不可以吃藥。",
          "error": "Should be 我不能吃藥 for inability; 不可以 implies permission denied."
        }
      ],
      "transformation_drills": ["Change 我可以吃藥嗎？ to 我可以吃藥丸嗎？", "Change 不可以吃藥 to 不能吃藥 for softer tone."],
      "production_drills": ["Ask the doctor: 我可以吃這個藥嗎？", "Tell the pharmacist: 我不可以吃藥水。"],
      "common_error_patterns": ["Confusing 不可以 (permission) with 不能 (ability)", "Using 可以 for ability instead of 會"],
      "repair_feedback": {
        "word_order": "Place 可以 before the verb.",
        "politeness": "Use 請問 before asking permission.",
        "vocabulary": "Use 可以 for permission, 會 for ability."
      }
    }
  ]
}
